from pydantic_ai import Agent, ResultValidator
from vex import Guardrail, Policy

ftc_claims_guardrail = Guardrail(
    name="ftc-product-claims",
    policy=Policy.BLOCK,
    validators=[
        "no_unsubstantiated_claims(product_description) == True",
        "contains_evidence_markers(description)"
    ]
)

class ProductDescriptionAgent(Agent):
    result_validator = ResultValidator(guards=[ftc_claims_guardrail])

    def generate_description(self, product_specs: dict) -> str:
        # AI generation logic
        return self._ai_call(product_specs)

from vex import Guardrail, Policy
privacy_guardrail = Guardrail(
    name="ccpa-gdpr-notice",
    policy=Policy.REQUIRE,
    validators=[
        "'To opt-out' in response or 'CCPA' in response",
        "no_pii_leakage(response, user_context)"
    ]
)

class PersonalizationAgent(Agent):
    result_validator = ResultValidator(
        guards=[privacy_guardrail],
        fallback_template="Your personalized results... [CCPA: Reply STOP to opt-out]"
    )

    def recommend_products(self, user_profile: dict) -> list:
        return self._ai_recommend(user_profile)
